const userData = $json.userData[0].json;
const restaurants = $json.allRestaurantsData.restaurant;

const userRestaurant = userData.userInputRestaurant.toLowerCase().trim();

const matchedRestaurant = restaurants.find(r => 
  r.name.toLowerCase().trim().includes(userRestaurant) || 
  userRestaurant.includes(r.name.toLowerCase().trim())
);

if (matchedRestaurant) {
  return [{
    json: {
      isRestaurantAvailable: 1,
      restaurantId: matchedRestaurant.restuarant_id,
      restaurantName: matchedRestaurant.name,
      userInputItem: userData.userInputItem,
      userInputRestaurant: userData.userInputRestaurant,
      userInputAddOns: userData.userInputAddOns,
      userMessage: userData.userMessage,
      userInputStatus: userData.userInputStatus
    }
  }];
} else {
  return [{
    json: {
      isRestaurantAvailable: 0,
      message: `No restaurant found matching "${userData.userInputRestaurant}"`,
      userInputItem: userData.userInputItem,
      userInputRestaurant: userData.userInputRestaurant,
      userInputAddOns: userData.userInputAddOns,
      userMessage: userData.userMessage,
      userInputStatus: userData.userInputStatus
    }
  }];
}

var chatInput = $input.first().json.body.chatInput
var sessionId = $input.first().json.body.sessionId

return [
  {
    json: {
      chatInput,
      sessionId
    }
  }
]

var languageSlug = String($input.first().json.body.languageSlug ?? '')
var latitude = String($input.first().json.body.latitude ?? '')
var longitude = String($input.first().json.body.longitude ?? '')
var distance = String($input.first().json.body.distance ?? '')
var pageNo = String($input.first().json.body.pageNo ?? '0')
var count = String($input.first().json.body.count ?? '0')
var userId = String($input.first().json.body.userId ?? '')
var userTimezone = String($input.first().json.body.userTimezone ?? '')
var responseFlag = String($input.first().json.body.responseFlag ?? '0')
var platform = String($input.first().json.body.platform ?? '')
var orderMode = String($input.first().json.body.orderMode ?? '0')
var food = String($input.first().json.body.food ?? '')
var appToken = String($input.first().json.body.appToken ?? '')
var auth = String($input.first().json.body.auth ?? '')
var category_id = String($input.first().json.body.category_id ?? '')
var offersFreeDelivery = String($input.first().json.body.offersFreeDelivery ?? '0')
var sortBy = String($input.first().json.body.sortBy ?? '')
var availability = String($input.first().json.body.availability ?? '')
var itemSearch = String($input.first().json.body.itemSearch ?? '')
var rawAuth = $input.first().json.headers['authorization']
var authorizationToken = rawAuth.startsWith('Bearer ') 
  ? rawAuth.slice(7)  // remove "Bearer " prefix
  : rawAuth

return [
  {
    json: {
      languageSlug,
      latitude,
      longitude,
      distance,
      pageNo,
      count,
      userId,
      userTimezone,
      responseFlag,
      platform,
      orderMode,
      food,
      appToken,
      auth,
      category_id,
      offersFreeDelivery,
      sortBy,
      availability,
      itemSearch,
      authorizationToken
    }
  }
]

return[
  {
    json: {
      userInputItem: $input.first().json.output.user_input_item,
      userInputRestaurant: $input.first().json.output.user_input_restaurant,
      userInputAddOns: $input.first().json.output.user_input_add_ons,
      userMessage: $input.first().json.output.user_message,
      userInputStatus: $input.first().json.output.user_input_status
    }
  }
]
